#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-07-23

# Regression test for scripts/stamp-whats-new.mjs
#
# Why this exists: the What's New generator shipped with zero tests (#3096), and
# an adversarial assessment then found a real defect — a `## ` header that fails
# the version regex (a prerelease like `8.85.0-rc.1`) silently merged its bullets
# into the PREVIOUS release. #3102 fixed the parser and added the WHATS_NEW_ROOT
# override so a trusted copy can run against fixtures. This locks in that fix and
# the marker/idempotency contract so neither regresses.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
GEN="$PROJECT_ROOT/scripts/stamp-whats-new.mjs"

RED=$'\033[0;31m'
GREEN=$'\033[0;32m'
NC=$'\033[0m'
PASS=0
FAIL=0
pass() { echo "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
fail() { echo "  ${RED}✗${NC} $1"; FAIL=$((FAIL + 1)); }

hash_of() { cksum "$1" | awk '{print $1"-"$2}'; }

# Build a fixture root: a CHANGELOG plus a README carrying the marker block.
# Returns the root dir on stdout.
make_root() {
  local dir
  dir=$(mktemp -d)
  printf '%s\n' "$1" > "$dir/CHANGELOG.md"
  cat > "$dir/README.md" <<'EOF'
# Fixture

## What's New

<!--ork:whats-new-->
<!--/ork-->

---
EOF
  echo "$dir"
}

run_gen() { WHATS_NEW_ROOT="$1" node "$GEN" "${@:2}"; }

# ── 1. prerelease header must not leak into the previous release ────────────
# The bug: bullets under an unparseable `## ` header were attributed to the
# prior version. `-rc.1]` fails the \d+\.\d+\.\d+ capture.
ROOT=$(make_root '# Changelog

## [8.85.0-rc.1](https://x/compare/a...b) (2026-08-01)

### Features

* **rc:** should NOT appear under 8.84.7 ([#1](u))

## [8.84.7](https://x/compare/c...d) (2026-07-23)

### Bug Fixes

* **real:** belongs to 8.84.7 ([#2](u))')
run_gen "$ROOT" >/dev/null
block=$(sed -n '/ork:whats-new/,/\/ork/p' "$ROOT/README.md")
if grep -q 'belongs to 8.84.7' <<<"$block" \
   && ! grep -q 'should NOT appear under 8.84.7' <<<"$block"; then
  pass "prerelease bullet is not merged into the previous release"
else
  fail "prerelease bullet leaked into 8.84.7 (parser regression)"
  sed 's/^/      /' <<<"$block"
fi
rm -rf "$ROOT"

# ── 2. release-please link soup is stripped, issue ref kept ─────────────────
ROOT=$(make_root '# Changelog

## [8.84.7](https://x/compare/c...d) (2026-07-23)

### Bug Fixes

* **demos:** repair the renderer ([#3099](https://x/issues/3099)) ([9db430d](https://x/commit/9db430d))')
run_gen "$ROOT" >/dev/null
line=$(grep -m1 'repair the renderer' "$ROOT/README.md")
if grep -q '(#3099)' <<<"$line" && ! grep -qE '9db430d|https://x/commit' <<<"$line"; then
  pass "commit link stripped, issue ref (#3099) kept"
else
  fail "link soup not cleaned: $line"
fi
rm -rf "$ROOT"

# ── 3. idempotent: a second run produces no change ──────────────────────────
ROOT=$(make_root '# Changelog

## [8.84.7](https://x/compare/c...d) (2026-07-23)

### Bug Fixes

* **x:** one ([#1](u))')
run_gen "$ROOT" >/dev/null
h1=$(hash_of "$ROOT/README.md")
run_gen "$ROOT" >/dev/null
h2=$(hash_of "$ROOT/README.md")
if [ "$h1" = "$h2" ]; then pass "idempotent (second run is a no-op)"; else fail "not idempotent"; fi
if run_gen "$ROOT" --check >/dev/null; then pass "--check passes on a fresh README"; else fail "--check flagged a fresh README"; fi
rm -rf "$ROOT"

# ── 4. missing markers must ERROR, not silently pass ────────────────────────
ROOT=$(mktemp -d)
printf '# Changelog\n\n## [8.84.7](https://x/c...d) (2026-07-23)\n\n* **x:** one ([#1](u))\n' > "$ROOT/CHANGELOG.md"
printf '# No markers here\n' > "$ROOT/README.md"
if run_gen "$ROOT" >/dev/null 2>&1; then
  fail "missing markers did not error"
else
  pass "missing markers error out (no silent pass)"
fi
rm -rf "$ROOT"

# ── 5. --check FAILS when the block is stale vs CHANGELOG ────────────────────
ROOT=$(make_root '# Changelog

## [8.84.7](https://x/compare/c...d) (2026-07-23)

### Bug Fixes

* **x:** one ([#1](u))')
run_gen "$ROOT" >/dev/null
# Mutate CHANGELOG so the stamped block is now stale.
printf '# Changelog\n\n## [8.84.8](https://x/compare/d...e) (2026-07-24)\n\n### Features\n\n* **y:** two ([#2](u))\n' > "$ROOT/CHANGELOG.md"
if run_gen "$ROOT" --check >/dev/null 2>&1; then
  fail "--check passed on a stale block (vacuous)"
else
  pass "--check fails on a stale block"
fi
rm -rf "$ROOT"

echo
echo "  ${GREEN}${PASS} passed${NC}, ${RED}${FAIL} failed${NC}"
[ "$FAIL" -eq 0 ]
